package arch.day50;

import java.util.*;

/**
 * Simulates CI breaking-change classification between two OpenAPI-style property sets.
 * Production: openapi-diff, Optic, Spectral oas3-unused-component, or Pact provider verify.
 * Spring: springdoc produces JSON; pipeline compares to main branch artifact.
 */
public class Day50Intermediate {

    enum Verdict { NON_BREAKING, BREAKING }

    static Verdict classify(String label, Set<String> oldReq, Set<String> newReq,
                            Set<String> oldOpt, Set<String> newOpt,
                            Map<String, String> oldTypes, Map<String, String> newTypes) {
        System.out.println("  Inputs: required " + new TreeSet<>(oldReq) + " -> " + new TreeSet<>(newReq));
        System.out.println("          optional " + new TreeSet<>(oldOpt) + " -> " + new TreeSet<>(newOpt));
        for (String k : oldTypes.keySet()) {
            String ot = oldTypes.get(k);
            String nt = newTypes.get(k);
            if (nt != null && !ot.equals(nt)) {
                System.out.println("  TYPE CHANGE: " + k + " " + ot + " -> " + nt);
                return Verdict.BREAKING;
            }
        }
        for (String r : oldReq) {
            if (!newReq.contains(r) && !newOpt.contains(r)) {
                System.out.println("  REMOVED PROPERTY (was required): " + r);
                return Verdict.BREAKING;
            }
        }
        return Verdict.NON_BREAKING;
    }

    static void runScenario(String title, Verdict expected, Runnable block) {
        System.out.println("--- Scenario: " + title + " ---");
        block.run();
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("=== OpenAPI Contract Diff Simulator (CI Gate) ===");
        System.out.println();

        // --- Scenario 1: happy path — new optional field only ---
        runScenario("1: happy path - additive optional field", Verdict.NON_BREAKING, () -> {
            Set<String> oldR = Set.of("orderId", "total");
            Set<String> newR = Set.of("orderId", "total");
            Set<String> oldO = Set.of("note");
            Set<String> newO = Set.of("note", "loyaltyTier");
            Map<String, String> oldT = Map.of("orderId", "string", "total", "number");
            Map<String, String> newT = new HashMap<>(oldT);
            newT.put("loyaltyTier", "string");
            Verdict v = classify("add optional", oldR, newR, oldO, newO, oldT, newT);
            System.out.println("  VERDICT: " + v + " (clients ignore unknown JSON fields)");
        });

        // --- Scenario 2: retry/replay — same spec compared twice (deterministic cache hit) ---
        runScenario("2: retry/replay - identical snapshots reproduce same verdict", Verdict.NON_BREAKING, () -> {
            final String cacheKey = "orders-get-200-schema-v3";
            Set<String> oldR = Set.of("id");
            Set<String> newR = Set.of("id");
            Set<String> oldO = Collections.emptySet();
            Set<String> newO = Set.of("sku");
            Map<String, String> t = Map.of("id", "string", "sku", "string");
            System.out.println("  Run A key=" + cacheKey);
            Verdict a = classify("replay A", oldR, newR, oldO, newO, t, t);
            System.out.println("  Run B key=" + cacheKey + " (same inputs)");
            Verdict b = classify("replay B", oldR, newR, oldO, newO, t, t);
            System.out.println("  VERDICT: A=" + a + " B=" + b + " (pipeline cache avoids flaky diffs)");
        });

        // --- Scenario 3: failure/edge — required field removed ---
        runScenario("3: failure - removed required field from response", Verdict.BREAKING, () -> {
            Set<String> oldR = Set.of("orderId", "status", "total");
            Set<String> newR = Set.of("orderId", "status");
            Set<String> oldO = Collections.emptySet();
            Set<String> newO = Collections.emptySet();
            Map<String, String> types = Map.of(
                "orderId", "string", "status", "string", "total", "number");
            Verdict v = classify("remove total", oldR, newR, oldO, newO, types, types);
            System.out.println("  VERDICT: " + v + " (codegen + client parsers break)");
        });

        // --- Scenario 4: edge — type change on existing property ---
        runScenario("4: edge case - same name, incompatible type", Verdict.BREAKING, () -> {
            Set<String> r = Set.of("id");
            Set<String> o = Collections.emptySet();
            Map<String, String> oldT = Map.of("id", "string");
            Map<String, String> newT = Map.of("id", "integer");
            Verdict v = classify("id type", r, r, o, o, oldT, newT);
            System.out.println("  VERDICT: " + v);
        });

        System.out.println("=== SECTION === Summary rules for OpenAPI evolution ===");
        System.out.println("Rule 1: Add optional response field     -> usually NON_BREAKING (Postel)");
        System.out.println("Rule 2: Add required response field     -> often BREAKING (strict clients)");
        System.out.println("Rule 3: Remove or rename field          -> BREAKING unless version bump + deprecation");
        System.out.println("Rule 4: Change type or format           -> BREAKING");
        System.out.println("Rule 5: Narrow enum (remove value)     -> BREAKING; widen enum -> often safe");
        System.out.println("Rule 6: Enforce in CI: diff + Spectral + consumer Pact together");
    }
}

package arch.day50;

import java.util.*;

/**
 * Advanced: OpenAPI-style operation record + breaking-change decision engine.
 * Spring: map to @Operation(operationId=...) and springdoc GroupedOpenApi slices.
 */
public class Day50Advanced {

    record OperationSpec(String method, String path, String operationId,
                         boolean deprecated, java.util.List<String> requiredScopes) {
        String stableKey() {
            return method.toUpperCase() + " " + path;
        }
    }

    record DiffResult(String category, String detail) {}

    static List<DiffResult> diffOperations(OperationSpec before, OperationSpec after) {
        List<DiffResult> out = new ArrayList<>();
        if (!before.path().equals(after.path()) || !before.method().equalsIgnoreCase(after.method())) {
            out.add(new DiffResult("PATH_METHOD", "path or method changed"));
        }
        if (!before.operationId().equals(after.operationId())) {
            out.add(new DiffResult("OPERATION_ID", "codegen/SDK method names may change"));
        }
        if (!before.deprecated() && after.deprecated()) {
            out.add(new DiffResult("DEPRECATION", "signal sunset; monitor traffic"));
        }
        Set<String> b = new TreeSet<>(before.requiredScopes());
        Set<String> a = new TreeSet<>(after.requiredScopes());
        if (!b.equals(a) && a.size() > b.size()) {
            out.add(new DiffResult("SECURITY", "stricter scopes -> may break clients"));
        }
        return out;
    }

    static String severity(List<DiffResult> diffs) {
        boolean codegenRisk = false;
        for (DiffResult d : diffs) {
            if ("PATH_METHOD".equals(d.category()) || "SECURITY".equals(d.category())) {
                return "BREAKING";
            }
            if ("OPERATION_ID".equals(d.category())) {
                codegenRisk = true;
            }
        }
        if (codegenRisk) {
            return "BREAKING_FOR_CODEGEN";
        }
        return "DOCUMENTATION_ONLY";
    }

    public static void main(String[] args) {
        // Block 1: operation metadata evolution
        System.out.println("=== BLOCK 1: Operation metadata (OpenAPI paths.*) ===");
        OperationSpec v1 = new OperationSpec("get", "/orders/{orderId}", "getOrder",
            false, List.of("orders:read"));
        OperationSpec v2 = new OperationSpec("get", "/orders/{orderId}", "getOrderById",
            true, List.of("orders:read", "orders:audit"));
        List<DiffResult> metaDiff = diffOperations(v1, v2);
        System.out.println("Before: " + v1);
        System.out.println("After : " + v2);
        for (DiffResult d : metaDiff) {
            System.out.println("  - " + d.category() + ": " + d.detail());
        }
        System.out.println("Severity: " + severity(metaDiff));
        System.out.println();

        // Block 2: decision logic trace (same path, additive security)
        System.out.println("=== BLOCK 2: Decision logic - codegen vs runtime ===");
        System.out.println("If operationId changes, Java interface generated for Feign/SDK renames.");
        System.out.println("If path changes, URL clients and API gateway routes must update.");
        System.out.println("If scopes tighten, OAuth token without new scope -> 403 at gateway.");
        System.out.println();

        // Block 3: reference table
        System.out.println("=== BLOCK 3: OpenAPI change - decision reference table ===");
        System.out.println("Change type              | Typical verdict   | Mitigation");
        System.out.println("Add optional JSON field  | Non-breaking      | Document in changelog");
        System.out.println("Remove response field    | Breaking          | Version bump + Sunset");
        System.out.println("Rename operationId       | Breaks codegen    | Keep stable IDs; alias in docs");
        System.out.println("Add required query param | Breaking          | Default or new /v2 path");
        System.out.println("Mark deprecated true     | Non-breaking      | Set Deprecation + Sunset headers");
        System.out.println("Tighten security scheme  | Breaking for some | Staged rollout + dual auth");
        System.out.println("Split GroupedOpenApi     | Doc-only          | Update gateway route groups");
        System.out.println("Error schema to RFC7807  | Breaking if shape | Major version + adapter layer");
        System.out.println("Remove enum value        | Breaking          | Clients switch exhaustively fail");
        System.out.println("Add x- vendor extension  | Usually safe      | Namespace under x-company-*");
        System.out.println("Change default response  | Risky             | Regenerate SDK + contract tests");
    }
}

