package arch.day50;

import java.util.*;

/**
 * Exercise: CI gate for OpenAPI response schema evolution on GET /orders/{orderId} 200.
 * <p>
 * Spring production mapping:
 * - springdoc-openapi emits /v3/api-docs; pipeline downloads JSON and extracts
 *   components.schemas.Order for the 200 response of GET /orders/{orderId}.
 * - Store baseline openapi.json per release tag in artifact repo; PR job diffs candidate.
 * - Optional: Spectral ruleset + openapi-diff for full document; this class is the
 *   minimal teachable core for "breaking vs additive" reasoning.
 */
public class Day50Exercise {

    enum Level { PASS, WARN, FAIL }

    static final class CiVerdict {
        final Level level;
        final List<String> reasons;

        CiVerdict(Level level, List<String> reasons) {
            this.level = level;
            this.reasons = reasons;
        }
    }

    /** Compare response schema snapshots (required, optional, property types). */
    static CiVerdict evaluate(String operationIdBase, String operationIdCand,
                              Set<String> reqBase, Set<String> reqCand,
                              Map<String, String> typesBase, Map<String, String> typesCand) {
        List<String> reasons = new ArrayList<>();
        Level worst = Level.PASS;

        for (String k : typesBase.keySet()) {
            String tb = typesBase.get(k);
            String tc = typesCand.get(k);
            if (tc == null) {
                reasons.add("RULE-BREAK-01 removed property '" + k + "' from schema");
                worst = Level.FAIL;
            } else if (!tb.equals(tc)) {
                reasons.add("RULE-BREAK-02 type change on '" + k + "': " + tb + " -> " + tc);
                worst = Level.FAIL;
            }
        }
        for (String r : reqBase) {
            if (!reqCand.contains(r)) {
                reasons.add("RULE-BREAK-03 required field '" + r + "' missing in candidate");
                worst = Level.FAIL;
            }
        }
        if (!operationIdBase.equals(operationIdCand) && worst == Level.PASS) {
            reasons.add("RULE-WARN-01 operationId changed; Feign/OpenAPI Generator method names drift");
            worst = Level.WARN;
        }
        if (reasons.isEmpty()) {
            reasons.add("No breaking rules triggered; additive optional fields allowed");
        }
        return new CiVerdict(worst, reasons);
    }

    static void runCase(String label, CiVerdict v) {
        System.out.println("--- " + label + " ---");
        System.out.println("CI_RESULT=" + v.level);
        for (String r : v.reasons) {
            System.out.println("REASON=" + r);
        }
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("=== Day 50 Exercise: OpenAPI schema CI gate ===");
        System.out.println("Operation: GET /orders/{orderId} response 200 schema slices");
        System.out.println();

        // Case 1: additive optional only -> PASS
        Map<String, String> baseTypes = new LinkedHashMap<>();
        baseTypes.put("orderId", "string");
        baseTypes.put("status", "string");
        Map<String, String> candTypes = new LinkedHashMap<>(baseTypes);
        candTypes.put("loyaltyTier", "string");

        runCase("PR-101: add optional loyaltyTier",
            evaluate("getOrder", "getOrder",
                Set.of("orderId", "status"), Set.of("orderId", "status"),
                baseTypes, candTypes));

        // Case 2: removed required total -> FAIL
        Map<String, String> b2 = new LinkedHashMap<>();
        b2.put("orderId", "string");
        b2.put("total", "number");
        Map<String, String> c2 = new LinkedHashMap<>();
        c2.put("orderId", "string");
        runCase("PR-102: drop total from Order",
            evaluate("getOrder", "getOrder",
                Set.of("orderId", "total"), Set.of("orderId"),
                b2, c2));

        // Case 3: same schema but operationId rename -> WARN
        Map<String, String> b3 = Map.of("orderId", "string");
        runCase("PR-103: rename operationId only",
            evaluate("getOrder", "getOrderById",
                Set.of("orderId"), Set.of("orderId"),
                b3, new LinkedHashMap<>(b3)));

        System.out.println("=== Summary ===");
        System.out.println("FAIL blocks merge until version bump + consumer sign-off.");
        System.out.println("WARN notifies platform to regenerate internal SDK in same release train.");
        System.out.println("PASS allows merge when Spectral + Pact (if any) also green.");
    }
}

